example.code:
const age = 20;

if (age >= 18) {
  console.log('Accès autorisé');
} else {
  console.log('Accès refusé');
}

// Condition avec plusieurs branches
const note = 75;
if (note >= 90) {
  console.log('Excellent');
} else if (note >= 60) {
  console.log('Bien');
} else {
  console.log('À améliorer');
}

// Forme courte : l'opérateur ternaire
const statut = age >= 18 ? 'majeur' : 'mineur';
console.log(statut); // 'majeur'
